   138→const TRAIL_DATA={"framework":"openclaw","trailName":"The Gateway Trail","stops":[{"name":"Channel Outpost","subtitle":"Message Arrives","concept":"Channel Plugins","landmarkType":"town","code":{"file":"extensions/whatsapp/src/plugin.ts","content":"// extensions/whatsapp/src/plugin.ts (conceptual)
import { ChannelPlugin } from '@openclaw/types'

export const whatsappPlugin: ChannelPlugin = {
  config: {
    listAccountIds(cfg) {
      return cfg.whatsapp?.accounts?.map(a => a.id) ?? []
    },
    async isConfigured(account) {
      return !!account.phoneNumber
    },
    resolveAccount(cfg, id) {
      return cfg.whatsapp.accounts.find(a => a.id === id)
    },
  },
