    if (line.trim().startsWith('#')) {
      return '<span style="color:#555555">' + escHtml(line) + '</span>';
    }
    var result = '';
    var i = 0;
    while (i < line.length) {
      // String literal (double or single quotes)
      if (line[i] === '"' || line[i] === "'") {
        var quote = line[i];
