      if (line[i] === '<' && i + 1 < line.length && line[i + 1] === '%') {
        var end = line.indexOf('%>', i + 2);
        if (end === -1) end = line.length - 2;
        end += 2;
        end = Math.min(end, line.length);
        result += '<span style="color:#FF55FF">' + escHtml(line.substring(i, end)) + '</span>';
        i = end;
        continue;
