        result += '<span style="color:#555555">' + escHtml(line.substring(i)) + '</span>';
        break;
      }
      // Symbol (colon followed by word)
      if (line[i] === ':' && i + 1 < line.length && /[a-zA-Z_]/.test(line[i + 1])) {
