function escHtml(s) {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function highlightCode(code) {
  return code.split('\n').map(function(line) {
    // Full-line comments (// or # or Blade comments)
    var trimmed = line.trim();
    if (trimmed.startsWith('//') || trimmed.startsWith('#') || trimmed.startsWith('{{--')) {
      return '<span style="color:#555555">' + escHtml(line) + '</span>';
    }
    var result = '';
    var i = 0;
    while (i < line.length) {
      // PHP variable ($identifier)
      if (line[i] === '$') {
        var end = i + 1;
        while (end < line.length && /[\w]/.test(line[end])) end++;
        result += '<span style="color:#FF55FF">' + escHtml(line.substring(i, end)) + '</span>';
        i = end;
        continue;
      }
      // String literal (single or double quotes)
      if (line[i] === "'" || line[i] === '"') {
        var quote = line[i];
        var end = i + 1;
        while (end < line.length && line[end] !== quote) {
          if (line[end] === '\\') end++;
          end++;
        }
        end = Math.min(end + 1, line.length);
        result += '<span style="color:#FFFF55">' + escHtml(line.substring(i, end)) + '</span>';
        i = end;
        continue;
      }
      // Inline comment (//)
      if (line[i] === '/' && i + 1 < line.length && line[i + 1] === '/') {
        result += '<span style="color:#555555">' + escHtml(line.substring(i)) + '</span>';
        break;
      }
      // Hash comment (#)
      if (line[i] === '#') {
        result += '<span style="color:#555555">' + escHtml(line.substring(i)) + '</span>';
        break;
      }
      // Arrow operator -> and double colon ::
      if (line[i] === '-' && i + 1 < line.length && line[i + 1] === '>') {
        result += '<span style="color:#AAAAAA">-&gt;</span>';
        i += 2;
        continue;
      }
      if (line[i] === ':' && i + 1 < line.length && line[i + 1] === ':') {
        result += '<span style="color:#AAAAAA">::</span>';
        i += 2;
        continue;
      }
      // Blade directives (@word)
      if (line[i] === '@' && i + 1 < line.length && /[a-zA-Z]/.test(line[i + 1])) {
        var end4 = i + 1;
        while (end4 < line.length && /[\w]/.test(line[end4])) end4++;
        result += '<span style="color:#55FFFF">' + escHtml(line.substring(i, end4)) + '</span>';
        i = end4;
        continue;
      }
      // Number
      if (/\d/.test(line[i]) && (i === 0 || !/\w/.test(line[i - 1]))) {
        var end2 = i;
        while (end2 < line.length && /[\d._]/.test(line[end2])) end2++;
        result += '<span style="color:#FF55FF">' + escHtml(line.substring(i, end2)) + '</span>';
        i = end2;
        continue;
      }
      // Identifier or keyword
      if (/[a-zA-Z_]/.test(line[i])) {
        var end3 = i;
        while (end3 < line.length && /[\w]/.test(line[end3])) end3++;
        var word = line.substring(i, end3);
        if (PHP_KEYWORDS.has(word)) {
          result += '<span style="color:#55FFFF">' + escHtml(word) + '</span>';
        } else {
          result += '<span style="color:#55FF55">' + escHtml(word) + '</span>';
        }
        i = end3;
        continue;
      }
      // Blade template syntax {{ }} and {!! !!}
      if (line[i] === '{' && i + 1 < line.length && line[i + 1] === '{') {
        result += '<span style="color:#55FFFF">' + escHtml('{{') + '</span>';
        i += 2;
        continue;
      }
      if (line[i] === '}' && i + 1 < line.length && line[i + 1] === '}') {
        result += '<span style="color:#55FFFF">' + escHtml('}}') + '</span>';
        i += 2;
        continue;
      }
      // Punctuation / operators
      result += '<span style="color:#AAAAAA">' + escHtml(line[i]) + '</span>';
      i++;
    }
    return result;
  }).join('\n');
}

