export function createChatRunRegistry(gateway: GatewayServer) {

  async function handleChatSend(
    sessionEntry: SessionEntry,
    message: InboundMessage,
  ) {
    sessionEntry.transcript.push({
      role: 'user',
      content: message.text,
      timestamp: Date.now(),
    })

    const agentRpc = gateway.acp.getClient(sessionEntry.agentId)
    const stream = await agentRpc.call('chat.send', {
      sessionId: sessionEntry.sessionKey,
      messages: sessionEntry.transcript,
      tools: sessionEntry.metadata.enabledTools,
      model: sessionEntry.metadata.model,
    })

    for await (const chunk of stream) {
      if (chunk.type === 'text') {
        gateway.broadcast('chat.stream', { text: chunk.text })
      } else if (chunk.type === 'tool_use') {
        const result = await executeTool(chunk.tool, chunk.input)
        agentRpc.sendToolResult(chunk.id, result)
      }
    }
    await saveSession(sessionEntry)
  }

  return { handleChatSend }
}","language":"typescript"},"narration":"The gateway server accepts WebSocket connections from channels, the CLI, and native apps. The streaming loop handles text and tool calls differently. Text streams in real time; tool calls get executed on the gateway and results feed back."},{"name":"Agent RPC Rapids","subtitle":"Talking to the AI","concept":"Gateway Control Plane","landmarkType":"river","code":{"file":"src/acp/client.ts","content":"// src/acp/client.ts (simplified)
export function createAcpClient(agentId: string, wsUrl: string) {
  const ws = new WebSocket(wsUrl)

  async function* call(
    method: string,
    params: ChatSendParams,
  ): AsyncGenerator<AgentChunk> {
    const requestId = crypto.randomUUID()

    ws.send(JSON.stringify({
      jsonrpc: '2.0',
      id: requestId,
      method,
      params,
    }))

    while (true) {
      const msg = await nextMessage(ws, requestId)
      if (msg.type === 'done') break
      yield msg
    }
  }

  function sendToolResult(toolCallId: string, result: ToolResult) {
    ws.send(JSON.stringify({
      jsonrpc: '2.0',
      method: 'tool.result',
      params: { toolCallId, result },
    }))
  }

  return { call, sendToolResult }
}","language":"typescript"},"narration":"Now we cross the RPC Rapids. The gateway and agent communicate over JSON-RPC. The agent decides what to do, but the gateway controls what actually happens on your machine. Security through architecture."},{"name":"Tool Execution Gorge","subtitle":"Running Commands on the Host","concept":"Gateway Control Plane","landmarkType":"forest","code":{"file":"src/agents/bash-tools.exec.ts","content":"// src/agents/bash-tools.exec.ts (simplified)
export async function executeBashTool(
  input: { command: string },
  context: ToolContext,
): Promise<ToolResult> {
  const { command } = input
  const { sessionEntry, securityPolicy } = context

  if (!securityPolicy.allowBash) {
    return { error: 'Bash execution not permitted' }
  }

  const pty = spawn('bash', ['-c', command], {
    cwd: sessionEntry.metadata.workingDir,
    env: { ...process.env, ...sessionEntry.metadata.env },
    timeout: 120_000,
  })

  let stdout = ''
  pty.onData(data => { stdout += data })
  const exitCode = await pty.wait()

  return {
    stdout: stdout.slice(0, 100_000),
    exitCode,
  }
}","language":"typescript"},"narration":"Deep in Tool Execution Gorge, the agent's intentions become real actions. Security check first, then a real PTY with a two-minute timeout. Bash is just one tool — same pattern for browser control, canvas, and device actions."},{"name":"Response Delivery Frontier","subtitle":"Back Through the Channel","concept":"Channel Plugins","landmarkType":"town","code":{"file":"src/gateway/server-channels.ts","content":"// src/gateway/server-channels.ts (simplified)
export function createChannelManager(gateway: GatewayServer) {

  async function deliverResponse(
    sessionEntry: SessionEntry,
    response: AgentResponse,
  ) {
    const { channel, peer, accountId } = sessionEntry.routing
    const plugin = gateway.channels.get(channel)

    const formatted = formatForChannel(channel, response.text, {
      maxLength: getChannelLimit(channel),
    })

    for (const chunk of formatted) {
      await plugin.send({ accountId, peer, text: chunk })
    }

    sessionEntry.transcript.push({
      role: 'assistant',
      content: response.text,
      timestamp: Date.now(),
    })
    await saveSession(sessionEntry)

    gateway.broadcast('chat.response', { text: response.text })
  }

  return { deliverResponse }
}","language":"typescript"},"narration":"You made it! The response travels back through the same channel. Formatted for each platform's limits, chunked automatically, saved to the transcript. Message in, intelligence applied, response out. Your wagon has arrived."}],"events":[{"type":"weather","trigger":"after_stop","triggerStop":1,"title":"Protocol Storm!","text":"A storm of messages hits your gateway — WhatsApp sends phone numbers, Discord sends snowflake IDs, Slack sends workspace tokens. How do you weather this storm?","choices":[{"text":"Define a common interface that all channel plugins must implement","correct":true,"explanation":"OpenClaw's ChannelPlugin interface forces every platform into the same shape. New channels can be added without touching gateway code."},{"text":"Write a giant switch statement in the gateway for each platform","correct":false,"explanation":"That would make the gateway a tangled mess. Every new channel means modifying core code."},{"text":"Only support one messaging platform to keep things simple","correct":false,"explanation":"Multi-channel support is core to OpenClaw's value. The trick is clean abstraction through the plugin interface."}],"concept":"Channel Plugins","difficulty":"easy"},{"type":"encounter","trigger":"after_stop","triggerStop":2,"title":"A Fellow Operator Appears","text":"A seasoned operator says: 'I run three agents — personal on WhatsApp, work on Slack, social bot on Discord. One gateway.' How does it know which agent handles which message?","choices":[{"text":"Route bindings in the config map channels, peers, and guilds to agents","correct":true,"explanation":"Config bindings map at multiple levels. Priority: peer, guild, team, account, channel, then default."},{"text":"Each agent runs its own separate gateway on a different port","correct":false,"explanation":"One gateway, multiple agents. Separate gateways would mean separate configs and connections."},{"text":"The user specifies which agent to use in every message","correct":false,"explanation":"Routing is automatic and invisible. The gateway figures it out from the config bindings."}],"concept":"Route Resolution","difficulty":"easy"},{"type":"river","trigger":"after_stop","triggerStop":3,"title":"The Session State River","text":"You've reached the boundary between stateless request handling and persistent memory. Your assistant needs to remember last week's conversation across a restart. How do you cross?","choices":[{"text":"Store sessions as JSON files on disk, loaded on demand per key","correct":true,"explanation":"Each session is a JSON file at a predictable path. No database needed. The file system IS the persistence layer."},{"text":"Keep all sessions in memory with a Redis cache","correct":false,"explanation":"In-memory state is lost on restart. Redis adds an external dependency. OpenClaw is local-first."},{"text":"Store history in the AI model's context and let it remember","correct":false,"explanation":"Context windows are limited and expensive. The persistence layer is separate from inference."}],"concept":"Session Persistence","difficulty":"medium"},{"type":"misfortune","trigger":"after_stop","triggerStop":5,"title":"Runaway Process!","text":"The AI agent ran a shell command that's an infinite loop consuming 100% CPU. Your gateway is grinding to a halt!","choices":[{"text":"Tool execution needs timeouts and session security policies should gate commands","correct":true,"explanation":"Bash tools have a two-minute timeout, and security policies control what's allowed. The gateway is the security boundary."},{"text":"The agent should be smarter and never request dangerous commands","correct":false,"explanation":"Never rely on the AI as the security boundary. Defense in depth means the gateway enforces limits."},{"text":"Run all tools in the agent's process so only it crashes","correct":false,"explanation":"Tools run on the gateway because they need local machine access. The separation is a feature."}],"concept":"Gateway Control Plane","difficulty":"medium"},{"type":"river","trigger":"after_stop","triggerStop":5,"title":"The RPC River","text":"The deepest river — the boundary between gateway and agent runtime. The agent needs a browser screenshot but runs in a different process. How?","choices":[{"text":"JSON-RPC over WebSocket: agent requests, gateway executes locally","correct":true,"explanation":"The agent streams tool_use blocks, the gateway intercepts and executes. The agent could run remotely."},{"text":"The agent directly imports and calls the browser module","correct":false,"explanation":"Separate processes can't call each other's code. The RPC boundary IS the security model."},{"text":"The agent writes commands to a shared file the gateway watches","correct":false,"explanation":"File watching is slow and unreliable. WebSocket RPC gives real-time bidirectional streaming."}],"concept":"Gateway Control Plane","difficulty":"hard"},{"type":"fortune","trigger":"after_stop","triggerStop":6,"title":"Spring of Clean Architecture","text":"Your understanding of the control plane is solid! Friendly contributors join your camp and share plugin templates.","choices":[],"concept":"Channel Plugins","difficulty":"easy"},{"type":"weather","trigger":"after_stop","triggerStop":6,"title":"Message Chunking Fog","text":"Dense fog. Your assistant wrote 3000 words but WhatsApp only allows 4096 characters. The user sees a truncated response. What went wrong?","choices":[{"text":"The formatter should chunk messages based on each channel's limit","correct":true,"explanation":"WhatsApp: 4096, Discord: 2000, Slack: 40000. The delivery layer splits into properly-sized chunks."},{"text":"Tell the AI to always write short responses","correct":false,"explanation":"You can't enforce output length on LLMs. The delivery layer handles formatting."},{"text":"Switch to a channel with no message limits","correct":false,"explanation":"Multi-channel means meeting users where they are. Every channel must work correctly."}],"concept":"Channel Plugins","difficulty":"easy"}],"partyMembers":[{"name":"Gateway Control Plane","icon":"gateway","maxHealth":3},{"name":"Channel Plugins","icon":"channel","maxHealth":3},{"name":"Route Resolution","icon":"route","maxHealth":3},{"name":"Session Persistence","icon":"session","maxHealth":3}],"deathMessages":["You have died of unhandled WebSocket disconnections.","You have died of missing default routes.","You have drowned in the RPC River.","You have died of session bloat.","You have died of a runaway bash command.","You have died of unhandled plugin exceptions.","You have died of API rate limits.","You have died of dependency conflicts.","You have died of expired sessions.","You have died of Discord snowflake avalanche.","You have died of invalid routing config."]};
